import { useState } from 'react';
import { ChevronDown, X, Shield, Brain, BarChart2, Globe, Award } from 'lucide-react';
import SectionHeader from './SectionHeader';

const groups = [
  {
    category: 'Cybersecurity',
    icon: <Shield size={16}/>,
    color: 'bg-teal/10 text-teal2 border-teal/20',
    accent: 'bg-teal',
    certs: [
      { org:'Google', name:'Cybersecurity Professional Certificate', badge:'🔄 In Progress', img: null },
      { org:'Sprints × Microsoft', name:'Cybersecurity Training', img: null },
      { org:'HP LIFE', name:'Cybersecurity Awareness', img: null },
    ],
  },
  {
    category: 'AI & Data',
    icon: <Brain size={16}/>,
    color: 'bg-amber/10 text-amber2 border-amber/20',
    accent: 'bg-amber',
    certs: [
      { org:'NVIDIA × ITI', name:'Gen AI Code Camp — LLM & RAG', img: null },
      { org:'IBM / Coursera', name:'Intro to Artificial Intelligence', img: null },
      { org:'Meta / Coursera', name:'Intro to Data Analytics', img: null },
      { org:'Dubai Future Foundation', name:'AI Prompt Engineering', img: null },
      { org:'HP LIFE', name:'Data Science & Analytics', img: null },
    ],
  },
  {
    category: 'Digital & Business',
    icon: <Globe size={16}/>,
    color: 'bg-coral/10 text-coral border-coral/20',
    accent: 'bg-coral',
    certs: [
      { org:'Google', name:'Digital Marketing Fundamentals', img: null },
      { org:'Banque Misr × Google', name:'Maharat Digital Marketing', img: null },
      { org:'HP LIFE', name:'Digital Business Skills', img: null },
    ],
  },
  {
    category: 'Tech & Other',
    icon: <BarChart2 size={16}/>,
    color: 'bg-lav/20 text-purple-600 border-lav/30',
    accent: 'bg-lav',
    certs: [
      { org:'Harvard / ITI', name:'CS50 Computer Science', img: null },
      { org:'EYouth', name:'Blockchain Technology', img: null },
      { org:'Edraak', name:'Meta Spark AR', img: null },
    ],
  },
];

const achievements = [
  { icon:'🥇', year:'2020 · National Level', title:'Scout Excellence — 1st Place', desc:'1st Place at the National Level in the Scout Excellence Competition — exceptional leadership & teamwork.', img: null },
  { icon:'🏆', year:'2019 · Asyut Directorate', title:'Scout Excellence — 1st Place', desc:'1st Place at the Asyut Directorate of Education Scout Competition — strong initiative and organizational skills.', img: null },
];

function ImageModal({ src, name, onClose }) {
  if (!src) return null;
  return (
    <div className="fixed inset-0 z-50 bg-ink/70 backdrop-blur-sm flex items-center justify-center p-4" onClick={onClose}>
      <div className="relative max-w-2xl w-full" onClick={e => e.stopPropagation()}>
        <button onClick={onClose} className="absolute -top-10 right-0 text-white/70 hover:text-white">
          <X size={24}/>
        </button>
        <img src={src} alt={name} className="w-full rounded-2xl shadow-2xl" />
        <p className="text-center text-white/60 text-sm mt-3">{name}</p>
      </div>
    </div>
  );
}

export default function Certs() {
  const [open, setOpen] = useState(null);
  const [modal, setModal] = useState(null);

  return (
    <>
      <section id="certs" className="py-24 px-[5%] bg-parchment">
        <SectionHeader tag="Credentials" title='<em class="italic text-amber not-italic font-serif-display">Certifications</em>' />
        <p className="text-sm text-muted mb-8 -mt-6">Click on any category to expand · Click on a cert to view</p>

        <div className="flex flex-col gap-3 max-w-3xl">
          {groups.map((g, gi) => (
            <div key={gi} className="reveal">
              {/* Group header — clickable */}
              <button
                onClick={() => setOpen(open === gi ? null : gi)}
                className={`w-full flex items-center justify-between px-5 py-4 rounded-2xl border ${g.color} transition-all hover:shadow-md`}>
                <div className="flex items-center gap-3">
                  <span>{g.icon}</span>
                  <span className="font-semibold text-sm">{g.category}</span>
                  <span className="text-xs opacity-60">({g.certs.length} certs)</span>
                </div>
                <ChevronDown size={16} className={`transition-transform duration-300 ${open===gi?'rotate-180':''}`}/>
              </button>

              {/* Expanded certs */}
              {open === gi && (
                <div className="mt-2 grid sm:grid-cols-2 gap-2 pl-2">
                  {g.certs.map((c, ci) => (
                    <div key={ci}
                      onClick={() => c.img && setModal(c)}
                      className={`relative bg-cream rounded-xl px-4 py-3.5 border-[1.5px] border-transparent overflow-hidden transition-all hover:border-amber/20 hover:-translate-y-0.5 hover:shadow-md ${c.img ? 'cursor-pointer' : 'cursor-default'} group`}>
                      <div className={`absolute top-0 left-0 right-0 h-[2px] ${g.accent} opacity-60 scale-x-0 group-hover:scale-x-100 transition-transform origin-left`} />
                      <div className="flex items-start justify-between gap-2">
                        <div>
                          <p className="text-[.6rem] font-semibold tracking-wider uppercase text-amber mb-1">{c.org}</p>
                          <p className="text-[.86rem] font-semibold text-ink2 leading-snug">{c.name}</p>
                        </div>
                        <div className="flex flex-col items-end gap-1 flex-shrink-0">
                          {c.badge && <span className="text-[.58rem] font-semibold bg-amber/15 text-amber2 px-2 py-0.5 rounded-full">{c.badge}</span>}
                          {c.img && <Award size={13} className="text-muted opacity-50 group-hover:opacity-100 group-hover:text-amber transition-all"/>}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      </section>

      {/* Achievements */}
      <section id="achievements" className="py-24 px-[5%] bg-cream">
        <SectionHeader tag="Recognition" title='<em class="italic text-teal not-italic font-serif-display">Achievements</em>' />
        <div className="grid md:grid-cols-2 gap-4 max-w-3xl">
          {achievements.map((a, i) => (
            <div key={i}
              onClick={() => a.img && setModal(a)}
              className={`reveal ${i===1?'delay-1':''} flex gap-4 items-start bg-parchment rounded-2xl p-6 border-[1.5px] border-transparent shadow-sm transition-all hover:border-amber/22 hover:-translate-y-1 hover:shadow-lg ${a.img?'cursor-pointer':'cursor-default'}`}>
              <div className="text-3xl bg-amber/8 p-3 rounded-xl flex-shrink-0 leading-none">{a.icon}</div>
              <div>
                <p className="text-[.65rem] font-semibold tracking-wider uppercase text-amber mb-1">{a.year}</p>
                <h3 className="font-serif-display text-lg tracking-tight mb-2">{a.title}</h3>
                <p className="text-[.85rem] text-muted2 leading-[1.7]">{a.desc}</p>
                {a.img && <p className="text-[.72rem] text-amber mt-2 flex items-center gap-1"><Award size={11}/> Click to view certificate</p>}
              </div>
            </div>
          ))}
        </div>
      </section>

      {modal && <ImageModal src={modal.img} name={modal.name || modal.title} onClose={() => setModal(null)} />}
    </>
  );
}
